async function seed() {
  console.log(`Seeding ${BANKS.length} vocabulary banks…`)
  let banksInserted = 0
  let wordsInserted = 0
  let skipped = 0

  for (const bank of BANKS) {
    const existing = await db.query.vocabBanks.findFirst({
      where: (t, { sql }) => sql`lower(${t.topic}) = lower(${bank.topic})`,
    })

    if (existing) {
      skipped++
      continue
    }

    const [inserted] = await db
      .insert(schema.vocabBanks)
      .values({
        topic: bank.topic,
        description: bank.description,
        isSystem: true,
        rank: 3,
      })
      .returning({ id: schema.vocabBanks.id })

    if (!inserted) continue
    banksInserted++

    await db.insert(schema.vocabBankWords).values(
      bank.words.map((w) => ({ ...w, bankId: inserted.id }))
    )
    wordsInserted += bank.words.length
  }

  console.log(`Done — ${banksInserted} banks inserted, ${wordsInserted} words inserted, ${skipped} banks already existed.`)
  await client.end()
}

seed().catch((err) => {
  console.error(err)
  process.exit(1)
})
